import{_ as s,o as e,c as n,ag as i}from"./chunks/framework.BZohXCq9.js";const g=JSON.parse('{"title":"Bamdra | 让 AI 真正进入真实工作","titleTemplate":false,"description":"Bamdra 希望让 AI 真正进入真实工作，扩展人的能力边界，并重塑日常工作流。了解 bamdra-openclaw-memory，体验面向 OpenClaw 的长期记忆能力。","frontmatter":{"layout":"home","title":"Bamdra | 让 AI 真正进入真实工作","titleTemplate":false,"description":"Bamdra 希望让 AI 真正进入真实工作，扩展人的能力边界，并重塑日常工作流。了解 bamdra-openclaw-memory，体验面向 OpenClaw 的长期记忆能力。","hero":{"name":"Bamdra","text":"由人赋能起飞，由智能扩展视野，最终回到人的掌控。","tagline":"Bamdra，中文名竹蜻蜓。我们相信，AI 不应该停留在演示和试用里，而应该通过一套由 3 个插件组成的 OpenClaw 记忆套件真正进入工作现场，帮助人处理复杂上下文、跨越中断、延续决策，并重新组织日常协作的方式。","image":{"src":"/images/Gemini_Generated_Image_fug6l2fug6l2fug6.jpg","alt":"Bamdra 品牌主视觉"},"actions":[{"theme":"brand","text":"查看产品介绍","link":"/zh/guide/openclaw-topic-memory"},{"theme":"alt","text":"下载安装资源","link":"/zh/guide/downloads"}]},"features":[{"icon":"🚀","title":"进入真实工作","details":"我们关注的是 AI 真正开始改变工作方式之后的价值，而不是停留在一次性的展示效果里。"},{"icon":"🧠","title":"OpenClaw 长期记忆","details":"让会话分支、稳定事实和上下文装配形成真正可用的连续性能力。"},{"icon":"⚙️","title":"能被正确接入","details":"以真实 release 包、真实配置和真实运行方式为基础，而不是用好看但不可落地的伪流程。"},{"icon":"📈","title":"改变工作流","details":"目标不只是把能力做出来，而是让团队减少重复、保持连续、重塑每天协作的节奏。"}]},"headers":[],"relativePath":"zh/index.md","filePath":"zh/index.md","lastUpdated":null}'),l={name:"zh/index.md"};function t(o,a,c,d,r,p){return e(),n("div",null,[...a[0]||(a[0]=[i('<div class="home-shell"><section class="home-panel hero-story"><div><h2>为什么叫竹蜻蜓</h2><p>竹蜻蜓并不是脱离人的飞行器，而是因为人的手赋予了它动力，它才得以起飞。飞起来之后，它会看到更广阔的世界、抵达更高的视角；但它最终仍然要回到人的手中，回到人的判断、人的目标与人的责任之内。Bamdra 这个名字，表达的正是我们对智能体的理解: AI 的价值来自人类赋予的目标，AI 的能力体现在帮助人拓展边界，而 AI 的最终归宿依然是服务于人类的决策与创造。</p></div><div class="story-accent"><p class="accent-kicker">愿景</p><h3>我们希望 AI 不再只停留在工作边缘，而是真正进入工作本身，改变人处理复杂事务的方式。</h3><p>不是替代人，而是让人能带着更多上下文前进，让被打断的工作重新连起来，让长期协作拥有更强的连续性与杠杆。</p></div></section><section class="home-panel"><h2>为什么现在需要 Bamdra</h2><div class="signal-grid"><div class="signal-item"><strong>OpenClaw</strong><span>围绕 OpenClaw 的真实使用链路打造，产品定位清晰，不做泛泛的概念包装。</span></div><div class="signal-item"><strong>SQLite</strong><span>默认即可落地，部署轻量，持久化可控，适合从个人到团队的连续使用。</span></div><div class="signal-item"><strong>工作流重塑</strong><span>真正有价值的不是“AI 能做什么”，而是它是否改变了团队每天协作、记录和延续工作的方式。</span></div><div class="signal-item"><strong>回到人手中</strong><span>AI 可以飞得更高、更远，但最终仍要回到人的目标、人的判断和人的责任之中。</span></div></div></section><section class="home-panel"><div class="section-heading"><p class="accent-kicker">产品套件</p><h2>三个插件，共同组成一套 continuity-first 记忆系统</h2><p>Bamdra 现在以 3 个公开插件组成套件发布。它们都可以独立运行，而主记忆插件在安装时也可以自动补齐自己的身份依赖。</p></div><div class="signal-grid"><div class="signal-item"><strong>bamdra-openclaw-memory</strong><span>主记忆运行时，负责话题连续性、上下文装配、事实存储和长会话恢复。</span></div><div class="signal-item"><strong>bamdra-user-bind</strong><span>身份与画像插件，负责把原始 channel 身份转换成稳定用户边界。它可以独立运行，也可以在安装主记忆插件时被自动补齐。</span></div><div class="signal-item"><strong>bamdra-memory-vector</strong><span>可选的语义召回增强层，在不引入重型外部基础设施的前提下，为记忆体系补充 Markdown + 向量检索能力。</span></div><div class="signal-item"><strong>为什么要拆分</strong><span>分仓库、分 npm 包、分发布职责之后，安装逻辑更清晰，安全边界更可靠，后续迭代也更容易管理。</span></div></div></section><section class="home-panel product-card"><div class="product-copy"><p class="accent-kicker">主入口插件</p><h2>bamdra-openclaw-memory 是这套产品的主入口</h2><p>bamdra-openclaw-memory 面向 OpenClaw 提供长期记忆能力。它能够分离话题分支、保存稳定事实、刷新摘要，并把当前上下文控制在更适合生产环境的体量里，让智能体在长会话中真正具备连续性。</p><p><code>bamdra-openclaw-memory</code> 本身可以独立运行。通过 npm 安装时，如果本地 OpenClaw 扩展目录里还没有 <code>bamdra-user-bind</code>，主插件会自动把这个依赖补齐进去。</p><p><code>bamdra-memory-vector</code> 则有意保持为独立、可选增强插件，只有你真的需要语义召回时才额外加上即可。</p><div class="inline-actions"><a class="contact-link" href="/zh/guide/products">查看全部产品</a><a class="contact-link" href="https://github.com/bamdra">访问 GitHub 首页</a></div></div><div class="product-meta"><ul><li><span>仓库地址</span><strong>bamdra/bamdra-openclaw-memory</strong></li><li><span>核心价值</span><strong>连续性不依赖 prompt 堆叠</strong></li><li><span>自动配套</span><strong>bamdra-user-bind</strong></li><li><span>可选增强</span><strong>bamdra-memory-vector</strong></li><li><span>部署方式</span><strong>SQLite 原生、带用户边界的上下文调度</strong></li></ul></div></section><section class="home-panel home-columns"><div class="info-card"><p class="accent-kicker">适用场景</p><h3>不是实验，而是工作中的协作能力</h3><ul class="clean-list"><li>产品与运营团队在多任务切换中保持上下文连续。</li><li>开发协作中长期保留约束、路径、环境信息与决策记录。</li><li>知识工作流里让稳定事实跨中断、跨重启继续发挥作用。</li></ul></div><div class="info-card"><p class="accent-kicker">它改变什么</p><h3>不只是部署成功，而是工作方式开始变化</h3><ul class="clean-list"><li>团队不必在每次回到旧任务时重讲一遍背景。</li><li>中断、切题和重启不再天然意味着上下文断裂。</li><li>偏好、路径、约束和决策能够在更长的工作周期里持续发挥作用。</li></ul></div></section><section class="home-panel download-panel"><div><p class="accent-kicker">立即开始</p><h2>下载当前发布版本</h2><p>从正式 release 包开始，再结合站点里的安装与运行说明，按真实方式接入 OpenClaw。</p></div><div class="inline-actions"><a class="contact-link" href="/downloads/bamdra-openclaw-memory-v0.3.1.zip">下载 v0.3.1</a><a class="contact-link" href="/zh/guide/downloads">进入下载中心</a></div></section></div>',1)])])}const v=s(l,[["render",t]]);export{g as __pageData,v as default};
